-- Add public flag and published_on to plans
ALTER TABLE plans ADD COLUMN public BOOLEAN DEFAULT false;

ALTER TABLE plans ADD COLUMN published_on DATE NULL;

-- Add name to users for creator attribution
ALTER TABLE users ADD COLUMN name VARCHAR(255) NULL;

